import React, { useState } from 'react';
import { MapPin, ArrowRight, Package, Truck, Calendar, Weight, Plus, ChevronRight } from 'lucide-react';
import Header from '../../components/Header';
import { jobs } from '../../api';
import { useApp } from '../../context/AppContext';
import './PostJob.css';

const VEHICLE_TYPES = [
  { id: 'suzuki', label: 'Suzuki Pickup', icon: '🛻', capacity: 'Up to 1 ton' },
  { id: 'hino_medium', label: 'Hino Medium', icon: '🚛', capacity: '1–5 tons' },
  { id: 'hino_large', label: 'Hino Large', icon: '🚚', capacity: '5–10 tons' },
  { id: 'container_20', label: 'Container 20ft', icon: '📦', capacity: '10–15 tons' },
  { id: 'container_40', label: 'Container 40ft', icon: '🏗️', capacity: '15–25 tons' },
  { id: 'flatbed', label: 'Flatbed', icon: '🚜', capacity: 'Heavy / OOG' },
  { id: 'reefer', label: 'Refrigerated', icon: '❄️', capacity: 'Cold chain' },
];

const ADDONS = [
  { id: 'labour', label: 'Loading Labour', icon: '💪' },
  { id: 'insurance', label: 'Cargo Insurance', icon: '🛡️' },
  { id: 'tracking', label: 'GPS Tracking', icon: '📍' },
  { id: 'packaging', label: 'Packaging', icon: '📦' },
  { id: 'fragile', label: 'Fragile Handling', icon: '⚠️' },
];

const STEPS = ['Route', 'Cargo', 'Vehicle', 'Review'];

export default function PostJob({ onBack, onSuccess }) {
  const { showToast } = useApp();
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(false);

  const [form, setForm] = useState({
    pickup_city: '',
    pickup_address: '',
    dropoff_city: '',
    dropoff_address: '',
    goods_type: '',
    weight_kg: '',
    description: '',
    vehicle_type: '',
    required_date: '',
    addons: [],
    budget_min: '',
    budget_max: '',
  });

  const set = (k) => (e) => setForm(f => ({ ...f, [k]: e.target.value }));

  const toggleAddon = (id) => {
    setForm(f => ({
      ...f,
      addons: f.addons.includes(id) ? f.addons.filter(a => a !== id) : [...f.addons, id],
    }));
  };

  const nextStep = () => {
    if (step === 0 && (!form.pickup_city || !form.dropoff_city)) {
      showToast('Please enter pickup and dropoff cities', 'error'); return;
    }
    if (step === 1 && (!form.goods_type || !form.weight_kg)) {
      showToast('Please fill in goods details', 'error'); return;
    }
    if (step === 2 && !form.vehicle_type) {
      showToast('Please select a vehicle type', 'error'); return;
    }
    setStep(s => s + 1);
  };

  const handleSubmit = async () => {
    if (!form.required_date) {
      showToast('Please select a required date', 'error'); return;
    }
    setLoading(true);
    try {
      const res = await jobs.create(form);
      showToast('Load posted! Carriers will send quotes soon 🎉', 'success');
      onSuccess?.(res.job);
    } catch (err) {
      showToast(err.message, 'error');
    } finally {
      setLoading(false);
    }
  };

  const progress = ((step) / (STEPS.length - 1)) * 100;

  return (
    <div className="post-job-screen">
      <Header title="Post a Load" showBack onBack={step > 0 ? () => setStep(s => s - 1) : onBack} />

      {/* Progress */}
      <div className="post-progress">
        <div className="progress-bar">
          <div className="progress-fill" style={{ width: `${progress}%` }} />
        </div>
        <div className="step-labels">
          {STEPS.map((s, i) => (
            <span key={s} className={`step-label ${i <= step ? 'active' : ''}`}>{s}</span>
          ))}
        </div>
      </div>

      <div className="post-content">

        {/* ── Step 0: Route ── */}
        {step === 0 && (
          <div className="step-card">
            <h2 className="step-title">Where are you shipping?</h2>

            <div className="route-box">
              <div className="route-row">
                <div className="route-dot pickup" />
                <div className="route-inputs">
                  <div className="form-group">
                    <label className="form-label">From City</label>
                    <input className="form-input" placeholder="e.g. Karachi" value={form.pickup_city} onChange={set('pickup_city')} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Pickup Address</label>
                    <input className="form-input" placeholder="Street / area / landmark" value={form.pickup_address} onChange={set('pickup_address')} />
                  </div>
                </div>
              </div>

              <div className="route-line" />

              <div className="route-row">
                <div className="route-dot dropoff" />
                <div className="route-inputs">
                  <div className="form-group">
                    <label className="form-label">To City</label>
                    <input className="form-input" placeholder="e.g. Lahore" value={form.dropoff_city} onChange={set('dropoff_city')} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Dropoff Address</label>
                    <input className="form-input" placeholder="Street / area / landmark" value={form.dropoff_address} onChange={set('dropoff_address')} />
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ── Step 1: Cargo ── */}
        {step === 1 && (
          <div className="step-card">
            <h2 className="step-title">What are you shipping?</h2>

            <div className="form-group">
              <label className="form-label">Goods Type</label>
              <select className="form-select" value={form.goods_type} onChange={set('goods_type')}>
                <option value="">Select goods type</option>
                <option>Cotton Bales</option>
                <option>Steel / Iron</option>
                <option>Furniture</option>
                <option>Electronics</option>
                <option>Chemicals</option>
                <option>Food / Grocery</option>
                <option>Construction Material</option>
                <option>Garments / Fabric</option>
                <option>Machinery</option>
                <option>Other</option>
              </select>
            </div>

            <div className="form-group">
              <label className="form-label">Weight (kg)</label>
              <input className="form-input" type="number" placeholder="e.g. 5000" value={form.weight_kg} onChange={set('weight_kg')} />
            </div>

            <div className="form-group">
              <label className="form-label">Description (optional)</label>
              <textarea className="form-textarea" placeholder="Any special instructions..." value={form.description} onChange={set('description')} />
            </div>

            <div className="form-group">
              <label className="form-label">Required By Date</label>
              <input className="form-input" type="date" value={form.required_date} onChange={set('required_date')}
                min={new Date().toISOString().split('T')[0]} />
            </div>

            <div className="form-group">
              <label className="form-label">Budget Range (PKR) — optional</label>
              <div className="budget-row">
                <input className="form-input" type="number" placeholder="Min" value={form.budget_min} onChange={set('budget_min')} />
                <span className="budget-sep">–</span>
                <input className="form-input" type="number" placeholder="Max" value={form.budget_max} onChange={set('budget_max')} />
              </div>
            </div>
          </div>
        )}

        {/* ── Step 2: Vehicle ── */}
        {step === 2 && (
          <div className="step-card">
            <h2 className="step-title">Vehicle & Add-ons</h2>

            <label className="form-label" style={{ marginBottom: 12 }}>Vehicle Type Required</label>
            <div className="vehicle-grid">
              {VEHICLE_TYPES.map(v => (
                <button
                  key={v.id}
                  className={`vehicle-btn ${form.vehicle_type === v.id ? 'active' : ''}`}
                  onClick={() => setForm(f => ({ ...f, vehicle_type: v.id }))}
                >
                  <span className="v-icon">{v.icon}</span>
                  <span className="v-label">{v.label}</span>
                  <span className="v-cap">{v.capacity}</span>
                </button>
              ))}
            </div>

            <div className="divider" />

            <label className="form-label" style={{ marginBottom: 12 }}>Add-on Services</label>
            <div className="addons-list">
              {ADDONS.map(a => (
                <button
                  key={a.id}
                  className={`addon-btn ${form.addons.includes(a.id) ? 'active' : ''}`}
                  onClick={() => toggleAddon(a.id)}
                >
                  <span>{a.icon} {a.label}</span>
                  <span className={`addon-check ${form.addons.includes(a.id) ? 'checked' : ''}`}>
                    {form.addons.includes(a.id) ? '✓' : '+'}
                  </span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ── Step 3: Review ── */}
        {step === 3 && (
          <div className="step-card">
            <h2 className="step-title">Review & Post</h2>

            <div className="review-card">
              <div className="review-row">
                <span className="r-label">Route</span>
                <span className="r-value">{form.pickup_city} → {form.dropoff_city}</span>
              </div>
              {form.pickup_address && (
                <div className="review-row">
                  <span className="r-label">Pickup</span>
                  <span className="r-value">{form.pickup_address}</span>
                </div>
              )}
              {form.dropoff_address && (
                <div className="review-row">
                  <span className="r-label">Dropoff</span>
                  <span className="r-value">{form.dropoff_address}</span>
                </div>
              )}
              <div className="review-row">
                <span className="r-label">Goods</span>
                <span className="r-value">{form.goods_type} — {form.weight_kg} kg</span>
              </div>
              <div className="review-row">
                <span className="r-label">Vehicle</span>
                <span className="r-value">{VEHICLE_TYPES.find(v => v.id === form.vehicle_type)?.label}</span>
              </div>
              <div className="review-row">
                <span className="r-label">Date</span>
                <span className="r-value">{form.required_date}</span>
              </div>
              {form.addons.length > 0 && (
                <div className="review-row">
                  <span className="r-label">Add-ons</span>
                  <span className="r-value">{form.addons.join(', ')}</span>
                </div>
              )}
              {(form.budget_min || form.budget_max) && (
                <div className="review-row">
                  <span className="r-label">Budget</span>
                  <span className="r-value">PKR {form.budget_min || '?'} – {form.budget_max || '?'}</span>
                </div>
              )}
            </div>

            <div className="post-info-box">
              <p>📢 Your load will be visible to all verified carriers. You'll receive quotes within minutes.</p>
            </div>
          </div>
        )}
      </div>

      <div className="post-footer">
        {step < STEPS.length - 1 ? (
          <button className="btn btn-primary btn-block btn-lg" onClick={nextStep}>
            Continue <ArrowRight size={18} />
          </button>
        ) : (
          <button className="btn btn-primary btn-block btn-lg" onClick={handleSubmit} disabled={loading}>
            {loading ? <div className="spinner" /> : '🚀 Post Load Now'}
          </button>
        )}
      </div>
    </div>
  );
}
